def _parse_startup_nodes(raw: str) -> List[Dict[str, Any]]:
    nodes = []
    for part in raw.split(","):
        part = part.strip()
        if not part:
            continue
        if ":" not in part:
            raise ValueError(f"Invalid Redis node address: {part}")
        host, port = part.rsplit(":", 1)
        nodes.append({"host": host.strip(), "port": int(port.strip())})
    if not nodes:
        raise ValueError("No Redis startup nodes provided")
    return nodes


