def _key(namespace: str, identifier: str) -> str:
    digest = hashlib.sha256(identifier.encode("utf-8")).hexdigest()
    return f"{namespace}:{digest}"


def _set_json(key: str, value: Dict[str, Any], ttl_seconds: int) -> bool:
    payload = json.dumps(value, separators=(",", ":"), ensure_ascii=False)
    return bool(redis_client.set(name=key, value=payload, ex=ttl_seconds))


def _get_json(key: str) -> Optional[Dict[str, Any]]:
    raw = redis_client.get(key)
    if raw is None:
        return None
    try:
        return json.loads(raw)
    except json.JSONDecodeError:
        return None


def _delete(key: str) -> bool:
    return redis_client.delete(key) > 0


